// ---- Unit system ----------------------------------------------------------
// MeadOS stores everything internally in METRIC (volume in litres, weight in
// kg) so every existing calculation keeps working untouched. The unit system
// is purely a presentation/input preference: it converts what the user sees
// and types. Conversion constants match standard brewing references.
var UNIT_VOL={metric:{label:'L',toSI:1},us:{label:'US gal',toSI:3.785411784},imperial:{label:'UK gal',toSI:4.54609}};
var UNIT_WT={metric:{label:'kg',toSI:1},us:{label:'lb',toSI:0.45359237},imperial:{label:'lb',toSI:0.45359237}};
function currentUnitSystem(){
  var u=APP.settings&&APP.settings.unitSystem;
  return (u==='us'||u==='imperial')?u:'metric';
}
function volUnitLabel(){return UNIT_VOL[currentUnitSystem()].label;}
function wtUnitLabel(){return UNIT_WT[currentUnitSystem()].label;}
// Convert a stored metric value → the current display unit (and back).
function volFromSI(litres){return litres/UNIT_VOL[currentUnitSystem()].toSI;}
function volToSI(v){return v*UNIT_VOL[currentUnitSystem()].toSI;}
function wtFromSI(kg){return kg/UNIT_WT[currentUnitSystem()].toSI;}
function wtToSI(w){return w*UNIT_WT[currentUnitSystem()].toSI;}
// Display a stored-litre volume in the user's unit, trimming trailing zeros
// ("9 L", "7.6 L", "2.01 US gal") so capacities read cleanly everywhere.
function fmtVol(litres){
  if(litres==null||isNaN(litres))return '—';
  var v=volFromSI(litres);
  return parseFloat(v.toFixed(2)).toString()+' '+volUnitLabel();
}
function fmtWt(kg){var w=wtFromSI(kg);return (currentUnitSystem()==='metric'?w.toFixed(2):w.toFixed(2))+' '+wtUnitLabel();}


